// Check if villa exists by searching v_uuid via custom endpoint
const token = $('HTTP Request').item.json.token;
const vUuid = $('Loop insert 1 villa').item.json.v_uuid;
const baseUrl = 'http://72.60.38.114:8080';

let villaExists = false;
let wpPropertyId = null;

try {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/wp-json/ibiza-beyond/v1/property/search-by-uuid/' + vUuid,
    headers: { 'Authorization': 'Bearer ' + token },
    json: true
  });
  if (res.status === 'found') {
    villaExists = true;
    wpPropertyId = res.property_id;
  }
} catch (e) {
  // Not found or error - treat as not exists
}

return [{
  json: {
    ...$('Loop insert 1 villa').item.json,
    villa_exists: villaExists,
    wp_property_id: wpPropertyId
  }
}];

// Photo Upload Node
// We attempt to upload images to WordPress Media /wp-json/wp/v2/media
// If successful, returns the array of uploaded Media IDs
// This runs BEFORE creating/updating the WP Rentals property so we can attach them.

const token = $('HTTP Request').item.json.token;
const baseUrl = 'http://72.60.38.114:8080';
const photos = $json.photos || [];
const uploadedImageIds = [];

if (!photos || photos.length === 0) {
    return [{ json: { ...$json, uploaded_images_ids: [] } }];
}

// We limit to max 10 photos to keep the testing fast
const photosToUpload = photos.slice(0, 10);

// For each photo, we download from Invenio and upload to WordPress Media
for (let i = 0; i < photosToUpload.length; i++) {
   const url = photosToUpload[i];
   try {
       // 1. Dwonload the image as binary
       const imageReq = await this.helpers.httpRequest({
           method: 'GET',
           url: url,
           encoding: null,
           resolveWithFullResponse: true
       });

       const imageBuffer = imageReq.body;
       const fileName = url.split('/').pop().split('?')[0] || `photo_${i}.jpg`;

       // 2. Upload to Wordpress Media
       const uploadRes = await this.helpers.httpRequest({
           method: 'POST',
           url: baseUrl + '/wp-json/wp/v2/media',
           headers: {
               'Authorization': 'Bearer ' + token,
               'Content-Disposition': `attachment; filename="${fileName}"`,
               'Content-Type': 'image/jpeg'
           },
           body: imageBuffer
       });

       if (uploadRes && uploadRes.id) {
           uploadedImageIds.push(uploadRes.id);
       }
   } catch(e) {
       console.log('Error uploading image ' + url, e.message);
   }
}

return [{ json: { ...$json, uploaded_images_ids: uploadedImageIds } }];
// NOTE: The IDs are now available as $json.uploaded_images_ids for Add/Edit nodes.

// After creating a new villa: save v_uuid as meta + set features
const token = $('HTTP Request').item.json.token;
const baseUrl = 'http://72.60.38.114:8080';
const propertyId = $json.property_id;
const vUuid = $('Loop insert 1 villa').item.json.v_uuid;
const features = $('Loop insert 1 villa').item.json.features || [];

// Save v_uuid
await this.helpers.httpRequest({
  method: 'POST',
  url: baseUrl + '/wp-json/ibiza-beyond/v1/property/' + propertyId + '/meta',
  headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
  body: JSON.stringify({ v_uuid: vUuid })
});

// Set features
if (features.length > 0) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/wp-json/ibiza-beyond/v1/property/' + propertyId + '/features',
    headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
    body: JSON.stringify({ features: features })
  });
}

return [{ json: { saved: true, villa_name: $('Loop insert 1 villa').item.json.villa_name, property_id: propertyId, features_count: features.length } }];

// After editing: ensure v_uuid + features are set
const token = $('HTTP Request').item.json.token;
const baseUrl = 'http://72.60.38.114:8080';
const propertyId = $('Check Villa Exists').item.json.wp_property_id;
const vUuid = $('Loop insert 1 villa').item.json.v_uuid;
const features = $('Loop insert 1 villa').item.json.features || [];

// Ensure v_uuid is saved
await this.helpers.httpRequest({
  method: 'POST',
  url: baseUrl + '/wp-json/ibiza-beyond/v1/property/' + propertyId + '/meta',
  headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
  body: JSON.stringify({ v_uuid: vUuid })
});

// Update features
if (features.length > 0) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/wp-json/ibiza-beyond/v1/property/' + propertyId + '/features',
    headers: { 'Authorization': 'Bearer ' + token, 'Content-Type': 'application/json' },
    body: JSON.stringify({ features: features })
  });
}

return [{ json: { updated: true, property_id: propertyId, features_count: features.length } }];
